import{_ as e,o as i,c as s,a3 as o}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Web.Docs","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/web-docs.md","filePath":"cosmos/framework/packages/web-docs.md","lastUpdated":1783216089000}'),t={name:"cosmos/framework/packages/web-docs.md"};function n(r,a,l,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="xihan-framework-web-docs" tabindex="-1">XiHan.Framework.Web.Docs <a class="header-anchor" href="#xihan-framework-web-docs" aria-label="Permalink to &quot;XiHan.Framework.Web.Docs&quot;">​</a></h1><blockquote><p>API 文档：在动态 API 之上提供 Scalar 与 Swagger UI 两套交互式文档界面，并按 <code>[DynamicApi]</code> 分组自动生成多份 OpenAPI 文档。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Web.Docs</code></li><li><strong>模块类</strong>：<code>XiHanWebDocsModule</code></li><li><strong>所在层</strong>：Web 层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Web.Docs 让你的 API 可视化、可试调。它基于 <a href="./web-api">Web.Api</a> 生成的 OpenAPI 文档，接入两套 UI：现代化的 <strong>Scalar</strong> 与经典的 <strong>Swagger UI</strong>，并根据动态 API 上的 <code>[DynamicApi]</code> 分组信息，为不同分组注册独立的 OpenAPI 文档（例如把系统接口与业务接口分开展示）。引用它、加上 <code>[DependsOn]</code>，启动后浏览器即可打开文档页面。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>想要一个交互式 API 文档界面，直接在浏览器里查看接口、参数并发起试调。</li><li>项目按 <code>[DynamicApi]</code> 分了组，希望文档也按组切换展示。</li><li>需要在 OpenAPI 中带上 XML 注释（接口/参数说明）。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Web.Docs</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanWebDocsModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>Scalar 文档界面</strong>：<code>OnApplicationInitialization</code> 中 <code>MapScalarApiReference(...)</code> 注册 Scalar，紫色主题、默认 C# <code>HttpClient</code> 示例，读取 <code>/openapi/{documentName}.json</code>，允许匿名访问。BasicApp 中访问路径为 <code>/scalar</code>。</li><li><strong>Swagger UI 文档界面</strong>：<code>OnPreApplicationInitialization</code> 中 <code>UseSwaggerUI(...)</code>（早于认证/授权中间件），逐个注册各分组的 SwaggerEndpoint。</li><li><strong>动态 API 分组发现</strong>：<code>DynamicApiSwaggerGroupHelper</code> 从 <code>[DynamicApi]</code> 特性收集分组定义，为默认文档与每个额外分组各注册一份 OpenAPI 文档。</li><li><strong>XML 注释增强</strong>：<code>AddOpenApi</code> 注册 <code>DynamicApiXmlCommentsOperationTransformer</code>，把 XML 文档注释注入 OpenAPI 操作。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>XiHanWebDocsModule</code></td><td>模块类，注册文档服务并挂载 Scalar / Swagger UI</td></tr><tr><td><code>DynamicApiSwaggerGroupHelper</code></td><td>从 <code>[DynamicApi]</code> 特性发现分组、默认文档名/标题</td></tr><tr><td><code>DynamicApiXmlCommentsOperationTransformer</code></td><td>将 XML 注释注入 OpenAPI 操作的转换器</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：<a href="./web-api">XiHan.Framework.Web.Api</a>（动态 API 与 OpenAPI 文档的来源）。</li><li>第三方核心：<code>Scalar.AspNetCore</code>（Scalar 文档界面）与 <code>Swashbuckle.AspNetCore</code>（Swagger UI）。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./web-api">XiHan.Framework.Web.Api</a> — 生成本包所展示的 OpenAPI 文档与动态 API 分组。</li><li><a href="./../concepts/dynamic-api">动态 API</a> — 动态 API 与 <code>[DynamicApi]</code> 分组约定。</li></ul>`,19)])])}const g=e(t,[["render",n]]);export{k as __pageData,g as default};
